INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'cl', 4, 1, NULL, 'João Calvino em Cl 4:1', 'Segundo João Calvino, a centralidade das Escrituras e da graça soberana ilumina o sentido deste texto. Colossenses 4 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'João Calvino', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1ts', 1, 1, NULL, 'Heinrich Bullinger em 1Ts 1:1', 'Na leitura de Heinrich Bullinger, vemos a centralidade das Escrituras e da graça soberana. 1 Tessalonicenses 1 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Heinrich Bullinger', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1ts', 2, 1, NULL, 'Dwight L. Moody em 1Ts 2:1', 'Segundo Dwight L. Moody, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. 1 Tessalonicenses 2 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Dwight L. Moody', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), '1ts', 3, 1, NULL, 'Joseph Benson em 1Ts 3:1', 'Na leitura de Joseph Benson, vemos a exposição textual com aplicação pastoral objetiva. 1 Tessalonicenses 3 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), '1ts', 4, 1, NULL, 'Martin Bucer em 1Ts 4:1', 'Martin Bucer interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em 1 Tessalonicenses 4, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1ts', 5, 1, NULL, 'Charles Finney em 1Ts 5:1', 'Charles Finney destaca o chamado ao arrependimento, fé viva e missão. Em 1 Tessalonicenses 5, o foco recai sobre evangelho da graça e vida em santidade e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Charles Finney', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), '2ts', 1, 1, NULL, 'Dwight L. Moody em 2Ts 1:1', 'Dwight L. Moody interpreta este versículo a partir de o chamado ao arrependimento, fé viva e missão. Em 2 Tessalonicenses 1, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Dwight L. Moody', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), '2ts', 2, 1, NULL, 'Joseph Benson em 2Ts 2:1', 'Joseph Benson destaca a exposição textual com aplicação pastoral objetiva. Em 2 Tessalonicenses 2, o foco recai sobre evangelho da graça e vida em santidade e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), '2ts', 3, 1, NULL, 'Martin Bucer em 2Ts 3:1', 'Na leitura de Martin Bucer, vemos a centralidade das Escrituras e da graça soberana. 2 Tessalonicenses 3 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em amor fraternal. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), '1tm', 1, 1, NULL, 'John Flavel em 1Tm 1:1', 'Segundo John Flavel, a piedade prática e a santificação do coração ilumina o sentido deste texto. 1 Timóteo 1 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em esperança escatológica. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'John Flavel', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1tm', 2, 1, NULL, 'E. M. Bounds em 1Tm 2:1', 'Na leitura de E. M. Bounds, vemos a coerência doutrinária aplicada à vida cristã. 1 Timóteo 2 evidencia evangelho da graça e vida em santidade como eixo da vida do povo de Deus, com ênfase em obediência da fé. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'E. M. Bounds', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '1tm', 3, 1, NULL, 'Atanásio em 1Tm 3:1', 'Atanásio interpreta este versículo a partir de a leitura cristológica e eclesial da passagem. Em 1 Timóteo 3, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo justiça com misericórdia. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Atanásio', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), '1tm', 4, 1, NULL, 'Thomas Watson em 1Tm 4:1', 'Thomas Watson destaca a piedade prática e a santificação do coração. Em 1 Timóteo 4, o foco recai sobre evangelho da graça e vida em santidade e chama a igreja para perseverança na tribulação. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), '1tm', 5, 1, NULL, 'Andrew Murray em 1Tm 5:1', 'Andrew Murray interpreta este versículo a partir de a coerência doutrinária aplicada à vida cristã. Em 1 Timóteo 5, Deus revela evangelho da graça e vida em santidade de forma pastoral e transformadora, promovendo fidelidade na aliança. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Andrew Murray', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), '1tm', 6, 1, NULL, 'Orígenes em 1Tm 6:1', 'Segundo Orígenes, a leitura cristológica e eclesial da passagem ilumina o sentido deste texto. 1 Timóteo 6 mostra que evangelho da graça e vida em santidade sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Orígenes', 'commentary', '#8B4513', NOW()),
